import os, sys; site_packages = os.path.join(sys.prefix, "Lib", "site-packages"); os.environ["PATH"] = os.path.join(site_packages, "nvidia", "cublas", "bin") + os.pathsep + os.path.join(site_packages, "nvidia", "cudnn", "bin") + os.pathsep + os.environ["PATH"]; import ctranslate2; from transformers import AutoTokenizer; tokenizer = AutoTokenizer.from_pretrained("facebook/nllb-200-distilled-600M", src_lang="eng_Latn"); translator = ctranslate2.Translator("nllb-200-600M-ct2", device="cpu"); source = tokenizer.convert_ids_to_tokens(tokenizer.encode("The Jedi and the Sith fight each other in the galaxy.")); target_prefix = ["heb_Hebr"]; results = translator.translate_batch([source], target_prefix=[target_prefix]); print("Tokens:", results[0].hypotheses[0]); target = results[0].hypotheses[0][1:]; print("Decoded:", tokenizer.decode(tokenizer.convert_tokens_to_ids(target), skip_special_tokens=True));
